import {
  axisFontProps,
  TICK_LINE_HEIGHT,
  TICK_LINE_ICON_OFFSET,
} from '../../constants.js';

/* A magic number to add a visual adjustment to match the tick position with the Figma proposal */
const VISUAL_ADJUSTMENT = 2;

export const getCategoryLeftAxisProps = (
  renderX: number,
  renderY: number,
  isVerticalLayout: boolean,
  maxSize: number,
  tickNameHasEmoji: boolean,
) => {
  const TICK_LINE_HEIGHT_VALIDATED = tickNameHasEmoji
    ? TICK_LINE_HEIGHT + TICK_LINE_ICON_OFFSET
    : TICK_LINE_HEIGHT;

  const x = isVerticalLayout
    ? renderX - maxSize / 2
    : renderX - maxSize - (TICK_LINE_HEIGHT_VALIDATED - VISUAL_ADJUSTMENT);
  const y = isVerticalLayout
    ? VISUAL_ADJUSTMENT * 2
    : renderY - TICK_LINE_HEIGHT_VALIDATED / 2;

  const foreignObjectInlineStyle = {
    height: TICK_LINE_HEIGHT_VALIDATED,
    width: maxSize + VISUAL_ADJUSTMENT * 4,
  };
  const foreignObjectContentInlineStyle = {
    ...axisFontProps,
    textAlign: isVerticalLayout ? 'center' : 'right',
    width: maxSize + VISUAL_ADJUSTMENT * 4,
  };

  return { x, y, foreignObjectInlineStyle, foreignObjectContentInlineStyle };
};
